    // Calculate additional metrics
    const burnRate = gameState.monthlyBurn;
    const netIncome = gameState.monthlyRevenue - burnRate;
    // Runway = how many months the current cash covers at the gross burn rate.
    // (Dividing by net burn blows up when revenue ~ covers burn, so we use gross
    // burn, which is always >= the base monthly burn.) isCashPositive still flags
    // profitability for the status label.
    const isCashPositive = gameState.runway > 0 && gameState.monthlyRevenue >= burnRate;
    const runwayMonths = gameState.runway > 0 ? gameState.runway / burnRate : 0;
    const averageRevenuePerCustomer = gameState.customers > 0 ? (gameState.monthlyRevenue / gameState.customers) : 0;
    const stressLevel = getStressLevel(gameState.stress);
    // Outcome cards (acknowledged events, opportunity choices) are pushed into
    // selectedCards for their impact, but they aren't counted in cardsGenerated.
    // Exclude them so the decision count/rate stays consistent (rate can't exceed 100%).
    const businessDecisionsCount = gameState.selectedCards.filter(card => card.category !== 'outcome').length;
    const decisionRate = gameState.cardsGenerated > 0 ? Math.round((businessDecisionsCount / gameState.cardsGenerated) * 100) : 0;
    
    // Update founded info with proper date
