// ---- Company section graphs (Chart.js) ----
// Live Chart instances, keyed by canvas id, so we can tear them down and rebuild
// each time the modal is (re)populated.
const companyCharts = {};

// Currently selected graph time range, in months. null = all time. Persists
// across modal re-populations so the chosen filter sticks.
let companyChartRangeMonths = 12;

// Collapse the raw history into one point per (rounded) in-game month, keeping the
// latest snapshot for each month. Also derives net new customers per month from
// the cumulative total. Returns the full series (range filtering happens later).
function getCompanyMonthlySeries() {
    const byMonth = new Map();
    (gameState.history || []).forEach(snap => {
        const bucket = Math.max(1, Math.round(snap.month));
        const prev = byMonth.get(bucket);
        // Keep the latest snapshot for rate/level metrics, but ACCUMULATE one-time costs —
        // several decisions can land in the same month, each with its own spend.
        const oneTimeCost = (prev ? prev.oneTimeCost || 0 : 0) + (snap.oneTimeCost || 0);
        byMonth.set(bucket, { ...snap, monthBucket: bucket, oneTimeCost });
    });
    const series = Array.from(byMonth.values()).sort((a, b) => a.monthBucket - b.monthBucket);
    let prevCustomers = 0;
    series.forEach(s => {
        s.newCustomers = s.customers - prevCustomers; // can be negative if churn occurs
        prevCustomers = s.customers;
    });
    return series;
}

// Limit a monthly series to the most recent `months` months (null = keep all).
function filterSeriesByRange(series, months) {
    if (!months || !series.length) return series;
    const latest = series[series.length - 1].monthBucket;
    return series.filter(s => s.monthBucket > latest - months);
}

// Whole years of history the company has accumulated (min 1). Drives the slider's
// upper bound, so the control auto-scales as the game runs longer.
function getHistoryMaxYears() {
    const series = getCompanyMonthlySeries();
    const maxMonth = series.length ? series[series.length - 1].monthBucket : 1;
    return Math.max(1, Math.ceil(maxMonth / 12));
}

// Human label for a slider value. The far end (value === maxYears) means all time.
function rangeLabelText(value, maxYears) {
    if (value >= maxYears) return 'All time';
    return value === 1 ? 'Last 1 year' : `Last ${value} years`;
}

// Slider position the persisted range corresponds to, clamped to the current max.
function rangeSliderValue(maxYears) {
    if (companyChartRangeMonths === null) return maxYears;
    return Math.min(maxYears, Math.max(1, Math.round(companyChartRangeMonths / 12)));
}

// Handle slider movement: update the persisted range + label, then re-slice the
// data into the existing charts. We update in place (no destroy/recreate) so
// dragging stays smooth even though oninput fires continuously.
function onCompanyRangeSlider(value, maxYears) {
    value = Number(value);
    maxYears = Number(maxYears);
    companyChartRangeMonths = value >= maxYears ? null : value * 12;
    const text = rangeLabelText(value, maxYears);
    const label = document.getElementById('chartRangeValue');
    if (label) label.textContent = text;
    const slider = document.getElementById('chartRangeSlider');
    if (slider) slider.setAttribute('aria-valuetext', text); // announce "Last N years"
    updateCompanyCharts();
}

// Format an in-game month number as a "Y# M#" axis label.
function companyMonthLabel(month) {
    const year = Math.floor((month - 1) / 12) + 1;
    const m = ((month - 1) % 12) + 1;
    return year > 1 ? `Y${year} M${m}` : `M${m}`;
}

// (Re)create a single Chart on the given canvas, destroying any previous instance.
function makeCompanyChart(canvasId, config) {
    const canvas = document.getElementById(canvasId);
    if (!canvas || typeof Chart === 'undefined') return;
    if (companyCharts[canvasId]) {
        companyCharts[canvasId].destroy();
        delete companyCharts[canvasId];
    }
    companyCharts[canvasId] = new Chart(canvas.getContext('2d'), config);
}

// Extract the plotted arrays for the current series. The dataset order here is the
// contract shared by the create path (chart configs below) and the update path
// (updateCompanyCharts) — keep them in sync.
function computeChartData(series) {
    return {
        labels: series.map(s => companyMonthLabel(s.monthBucket)),
        financial: [
            series.map(s => Math.round(s.monthlyRevenue)),
            series.map(s => Math.round(s.monthlyBurn)),
            series.map(s => Math.round(s.netIncome)),
            series.map(s => Math.round(s.oneTimeCost || 0))
        ],
        customer: [
            series.map(s => s.newCustomers),
            series.map(s => s.customers)
        ],
        business: [
            series.map(s => s.confidence),
            series.map(s => s.credibility),
            series.map(s => s.reach)
        ],
        operations: [
            series.map(s => s.teamSize),
            series.map(s => s.stress)
        ]
    };
}

// Human description of the active range, for screen-reader summaries.
function describeChartRange() {
    if (companyChartRangeMonths === null) return 'all time';
    const years = Math.round(companyChartRangeMonths / 12);
    return years <= 1 ? 'the last year' : `the last ${years} years`;
}

// Refresh each canvas's aria-label so screen readers get a spoken summary of what
// the (otherwise opaque) chart currently shows. Re-run whenever the data changes.
function updateChartAccessibility(series) {
    const setAria = (id, text) => {
        const el = document.getElementById(id);
        if (el) el.setAttribute('aria-label', text);
    };
    if (series.length < 2) {
        ['financialChart', 'customerChart', 'businessChart', 'operationsChart']
            .forEach(id => setAria(id, 'Chart: not enough data yet — make a few decisions to see trends over time.'));
        return;
    }
    const last = series[series.length - 1];
    const range = describeChartRange();
    setAria('financialChart',
        `Financial trend over ${range}. Latest monthly revenue ${formatCurrency(last.monthlyRevenue)}, burn ${formatCurrency(last.monthlyBurn)}, net income ${formatCurrency(last.netIncome)}`
        + (last.oneTimeCost ? `, one-time costs ${formatCurrency(last.oneTimeCost)}` : '') + '.');
    setAria('customerChart',
        `Customer growth over ${range}. ${last.customers.toLocaleString()} total customers, ${Math.round(last.newCustomers).toLocaleString()} new in the latest month.`);
    setAria('businessChart',
        `Business development over ${range}. Confidence ${last.confidence}%, credibility ${last.credibility}%, reach ${last.reach}%.`);
    setAria('operationsChart',
        `Operations over ${range}. Team size ${last.teamSize}, founder stress ${last.stress}%.`);
}

// Show the "not enough data" overlay on each chart when the window has < 2 points,
// without destroying the chart instances underneath.
function applyChartEmptyState(isEmpty) {
    ['financialChartWrap', 'customerChartWrap', 'businessChartWrap', 'operationsChartWrap']
        .forEach(id => {
            const wrap = document.getElementById(id);
            if (wrap) wrap.classList.toggle('is-empty', isEmpty);
        });
}

// Full (re)build of all four charts. Used when the modal opens, since the canvases
// are recreated each time the body's innerHTML is rebuilt.
function renderCompanyCharts() {
    if (typeof Chart === 'undefined') return; // CDN failed to load — skip gracefully
    const series = filterSeriesByRange(getCompanyMonthlySeries(), companyChartRangeMonths);
    const d = computeChartData(series);

    const baseOptions = {
        responsive: true,
        maintainAspectRatio: false,
        // Short, eased animation so scrubbing the range slider morphs the charts
        // smoothly. Kept brief (vs. Chart.js's 1s default) so rapid drags keep up.
        animation: { duration: 250, easing: 'easeOutQuart' },
        interaction: { mode: 'index', intersect: false },
        plugins: {
            legend: { labels: { boxWidth: 12, font: { size: 11 } } },
            tooltip: { enabled: true }
        },
        elements: { line: { tension: 0.3, borderWidth: 2 }, point: { radius: 2, hoverRadius: 4 } },
        scales: {
            x: { grid: { display: false }, ticks: { font: { size: 10 }, maxRotation: 0, autoSkipPadding: 8 } },
            y: { beginAtZero: true, ticks: { font: { size: 10 } } }
        }
    };
    const currencyTicks = { callback: (v) => formatCurrency(v), font: { size: 10 } };

    // Financial: monthly revenue vs. burn vs. net income (lines, left axis) +
    // one-time costs (bars, right axis — they're lump spends, not a monthly rate)
    makeCompanyChart('financialChart', {
        type: 'line',
        data: {
            labels: d.labels,
            // Dataset order MUST match computeChartData().financial so the update path
            // (applyChartData maps array[i] → datasets[i]) stays in sync. Visual stacking
            // (bar behind lines) is handled by the `order` property, not array position.
            datasets: [
                { label: 'Revenue', data: d.financial[0], borderColor: '#10b981', backgroundColor: 'rgba(16,185,129,0.08)', fill: true, yAxisID: 'y', order: 0 },
                { label: 'Burn', data: d.financial[1], borderColor: '#ef4444', backgroundColor: 'rgba(239,68,68,0.05)', fill: false, yAxisID: 'y', order: 0 },
                { label: 'Net Income', data: d.financial[2], borderColor: '#3b82f6', backgroundColor: 'rgba(59,130,246,0.05)', fill: false, yAxisID: 'y', order: 0 },
                { type: 'bar', label: 'One-time cost', data: d.financial[3], backgroundColor: 'rgba(234,88,12,0.30)', borderColor: 'rgba(234,88,12,0.8)', borderWidth: 1, yAxisID: 'yOneTime', order: 1 }
            ]
        },
        options: {
            ...baseOptions,
            scales: {
                x: baseOptions.scales.x,
                y: { beginAtZero: false, ticks: currencyTicks },
                yOneTime: { type: 'linear', position: 'right', beginAtZero: true, grid: { drawOnChartArea: false }, ticks: currencyTicks }
            },
            plugins: {
                ...baseOptions.plugins,
                tooltip: { callbacks: { label: (c) => `${c.dataset.label}: ${formatCurrency(c.parsed.y)}` + (c.dataset.label === 'One-time cost' ? '' : '/mo') } }
            }
        }
    });

    // Customer: total customers (line, left axis) + net new customers/mo (bars, right axis)
    makeCompanyChart('customerChart', {
        type: 'bar',
        data: {
            labels: d.labels,
            datasets: [
                { type: 'bar', label: 'New / mo', data: d.customer[0], backgroundColor: 'rgba(96,165,250,0.45)', borderColor: 'rgba(96,165,250,0.85)', borderWidth: 1, yAxisID: 'yNew', order: 1 },
                { type: 'line', label: 'Total Customers', data: d.customer[1], borderColor: '#2563eb', backgroundColor: 'rgba(37,99,235,0.10)', fill: true, yAxisID: 'yTotal', order: 0 }
            ]
        },
        options: {
            ...baseOptions,
            scales: {
                x: baseOptions.scales.x,
                yTotal: { type: 'linear', position: 'left', beginAtZero: true, ticks: { font: { size: 10 } } },
                yNew: { type: 'linear', position: 'right', beginAtZero: true, grid: { drawOnChartArea: false }, ticks: { precision: 0, font: { size: 10 } } }
            },
            plugins: {
                ...baseOptions.plugins,
                tooltip: { callbacks: { label: (c) => `${c.dataset.label}: ${Math.round(c.parsed.y).toLocaleString()}` } }
            }
        }
    });

    // Business Development: confidence, credibility, reach (all 0–100)
    makeCompanyChart('businessChart', {
        type: 'line',
        data: {
            labels: d.labels,
            datasets: [
                { label: 'Confidence', data: d.business[0], borderColor: '#7c3aed', backgroundColor: 'rgba(124,58,237,0.06)', fill: false },
                { label: 'Credibility', data: d.business[1], borderColor: '#db2777', backgroundColor: 'rgba(219,39,119,0.06)', fill: false },
                { label: 'Reach', data: d.business[2], borderColor: '#0891b2', backgroundColor: 'rgba(8,145,178,0.06)', fill: false }
            ]
        },
        options: {
            ...baseOptions,
            scales: { x: baseOptions.scales.x, y: { beginAtZero: true, max: 100, ticks: { font: { size: 10 } } } }
        }
    });

    // Operations: team size (count, left axis) vs. founder stress (%, right axis)
    makeCompanyChart('operationsChart', {
        type: 'line',
        data: {
            labels: d.labels,
            datasets: [
                { label: 'Team Size', data: d.operations[0], borderColor: '#d97706', backgroundColor: 'rgba(217,119,6,0.10)', fill: true, yAxisID: 'yTeam' },
                { label: 'Stress %', data: d.operations[1], borderColor: '#dc2626', backgroundColor: 'rgba(220,38,38,0.05)', fill: false, yAxisID: 'yStress' }
            ]
        },
        options: {
            ...baseOptions,
            scales: {
                x: baseOptions.scales.x,
                yTeam: { type: 'linear', position: 'left', beginAtZero: true, ticks: { precision: 0, font: { size: 10 } }, title: { display: false } },
                yStress: { type: 'linear', position: 'right', beginAtZero: true, max: 100, grid: { drawOnChartArea: false }, ticks: { font: { size: 10 } } }
            }
        }
    });

    applyChartEmptyState(series.length < 2);
    updateChartAccessibility(series);
}

// Push freshly sliced data into one existing chart and repaint without animation.
function applyChartData(canvasId, labels, dataArrays) {
    const chart = companyCharts[canvasId];
    if (!chart) return;
    chart.data.labels = labels;
    dataArrays.forEach((arr, i) => {
        if (chart.data.datasets[i]) chart.data.datasets[i].data = arr;
    });
    chart.update(); // uses the chart's short configured animation (see baseOptions)
}

// Lightweight redraw used while dragging the range slider: re-slice the series and
// update the existing chart instances in place instead of tearing them down.
function updateCompanyCharts() {
    if (typeof Chart === 'undefined') return;
    // If the charts haven't been built yet (e.g. first open), fall back to a full build.
    if (!companyCharts.financialChart) { renderCompanyCharts(); return; }
    const series = filterSeriesByRange(getCompanyMonthlySeries(), companyChartRangeMonths);
    const d = computeChartData(series);
    applyChartData('financialChart', d.labels, d.financial);
    applyChartData('customerChart', d.labels, d.customer);
    applyChartData('businessChart', d.labels, d.business);
    applyChartData('operationsChart', d.labels, d.operations);
    applyChartEmptyState(series.length < 2);
    updateChartAccessibility(series);
}

// Toggle between the Metrics and Org Chart panes inside the company modal.
function switchCompanyTab(tab) {
    const metricsPane = document.getElementById('companyMetricsBody');
    const orgPane = document.getElementById('companyOrgBody');
    const metricsTab = document.getElementById('companyTabMetrics');
    const orgTab = document.getElementById('companyTabOrg');
    if (!metricsPane || !orgPane) return;

    const showOrg = tab === 'org';

    metricsPane.hidden = showOrg;
    metricsPane.classList.toggle('active', !showOrg);
    orgPane.hidden = !showOrg;
    orgPane.classList.toggle('active', showOrg);

    metricsTab.classList.toggle('active', !showOrg);
    metricsTab.setAttribute('aria-selected', String(!showOrg));
    orgTab.classList.toggle('active', showOrg);
    orgTab.setAttribute('aria-selected', String(showOrg));

    if (showOrg) populateOrgChart();
}

// Persist the player's CEO name as they type (used elsewhere later).
function updateCeoName(value) {
    gameState.ceoName = value;
}

// Build up-to-two-letter initials from a person's name for the avatar circle.
function orgInitials(name) {
    const parts = (name || '').trim().split(/\s+/).filter(Boolean);
    if (!parts.length) return '?';
    const letters = parts.length === 1
        ? parts[0].slice(0, 2)
        : parts[0][0] + parts[parts.length - 1][0];
    return letters.toUpperCase();
}

// Render the org chart: the player as CEO up top, then hired employees laid out
// in seniority tiers (Senior above Mid above Junior). Re-rendered each time the
// Org Chart tab is opened so newly hired slots appear.
function populateOrgChart() {
    const body = document.getElementById('companyOrgBody');
    if (!body) return;

    const employees = gameState.employees || [];
    const byLevel = { Senior: [], Mid: [], Junior: [] };
    const coFounders = [];
    // Tag each employee with its index in gameState.employees so the action buttons
    // act on the right person regardless of tier sorting. Co-founders are pulled out
    // and shown up top alongside the CEO instead of in the seniority tiers.
    employees.forEach((e, i) => {
        if (e.coFounder) { coFounders.push({ emp: e, idx: i }); return; }
        (byLevel[e.level] || byLevel.Mid).push({ emp: e, idx: i });
    });
    // Within a tier, group the same roles together (e.g. all Sr. PMs side by side).
    Object.values(byLevel).forEach(arr => arr.sort((a, b) => a.emp.role.localeCompare(b.emp.role)));

    const hasCoFounder = coFounders.length > 0;
    const tiers = [
        ['Senior', 'Senior'],
        ['Mid', 'Mid-Level'],
        ['Junior', 'Junior']
    ];

    const nodeHTML = ({ emp: e, idx }) => {
        const tenure = formatTenure(employeeYearsOfService(e));
        const safeName = (e.name || '').replace(/"/g, '&quot;');
        // Right-side action: promote for Junior/Mid; "make co-founder" for a Senior
        // when no co-founder exists yet; otherwise a spacer to keep the avatar centered.
        let rightAction;
        if (e.level !== 'Senior') {
            rightAction = `<button type="button" class="org-action org-promote" onclick="promoteEmployee(${idx})"
                title="Promote ${safeName}" aria-label="Promote ${safeName}">▲</button>`;
        } else if (!hasCoFounder) {
            rightAction = `<button type="button" class="org-action org-cofound" onclick="makeCoFounder(${idx})"
                title="Make ${safeName} a co-founder" aria-label="Make ${safeName} a co-founder">★</button>`;
        } else {
            rightAction = `<span class="org-action org-action-spacer" aria-hidden="true"></span>`;
        }
        return `
        <div class="org-node org-level-${e.level.toLowerCase()}">
            <div class="org-node-top">
                <button type="button" class="org-action org-fire" onclick="fireEmployee(${idx})"
                    title="Lay off ${safeName}" aria-label="Lay off ${safeName}">✕</button>
                <div class="org-avatar org-avatar-initials">${orgInitials(e.name)}</div>
                ${rightAction}
            </div>
            <div class="org-name">${e.name || e.role}</div>
            <div class="org-title">${e.role}</div>
            <div class="org-meta">
                <span class="org-badge org-badge-${e.level.toLowerCase()}">${e.level}</span>
                <span class="org-salary">$${Math.round(e.salary / 1000)}k</span>
            </div>
            <div class="org-tenure">${tenure} of service</div>
        </div>
    `;
    };

    const coFounderNodeHTML = ({ emp: e }) => `
        <div class="org-node org-ceo org-cofounder">
            <div class="org-ceo-label">CO-FOUNDER</div>
            <div class="org-cofounder-name">${e.name || e.role}</div>
            <div class="org-role">${e.role} · ${e.equity || 0}% equity</div>
        </div>
    `;

    const tierRows = tiers
        .filter(([key]) => byLevel[key].length)
        .map(([key, label]) => `
            <div class="org-tier">
                <div class="org-tier-label">${label}</div>
                <div class="org-row">${byLevel[key].map(nodeHTML).join('')}</div>
            </div>
        `).join('');

    const ceoName = (gameState.ceoName || '');
    const tieredCount = employees.length - coFounders.length;
    const founders = 1 + coFounders.length;

    body.innerHTML = `
        <div class="org-chart">
            <div class="org-row org-ceo-row">
                <div class="org-node org-ceo">
                    <div class="org-ceo-label">CEO</div>
                    <input type="text" class="org-ceo-name" id="orgCeoName"
                        placeholder="Your name" value="${ceoName.replace(/"/g, '&quot;')}"
                        oninput="updateCeoName(this.value)" aria-label="Your name (CEO)" />
                    <div class="org-role">Chief Executive Officer · Founder</div>
                </div>
                ${coFounders.map(coFounderNodeHTML).join('')}
            </div>
            ${tieredCount ? '<div class="org-trunk"></div>' : ''}
            <div class="org-tiers">
                ${tierRows}
            </div>
            ${employees.length
                ? `<div class="org-footnote">${tieredCount} employee${tieredCount === 1 ? '' : 's'} · ${founders} founder${founders === 1 ? '' : 's'}</div>`
                : '<div class="org-empty">No employees yet. Hire team members to grow your org chart.</div>'}
        </div>
    `;
}

// Render a month count as "Y M" with fractional months, e.g. 63.43 -> "5Y 3.43M".
// Under a year it drops the "Y" part (e.g. "3.43M"). Used for the runway readout.
function formatMonthsDuration(totalMonths) {
    totalMonths = Math.max(0, totalMonths);
    const years = Math.floor(totalMonths / 12);
    const months = totalMonths - years * 12;
    return years > 0 ? `${years}Y ${months.toFixed(2)}M` : `${months.toFixed(2)}M`;
}

function formatCurrency(amount) {
    const absAmount = Math.abs(amount);
    const isNegative = amount < 0;
    const prefix = isNegative ? '-$' : '$';
    
    if (absAmount >= 1000000) {
        return prefix + (absAmount / 1000000).toFixed(1) + 'M';
    } else if (absAmount >= 1000) {
        return prefix + (absAmount / 1000).toFixed(1) + 'K';
    } else {
        return prefix + absAmount.toFixed(0);
    }
}

function exportCompanyReport() {
    const reportData = {
        companyName: document.getElementById('companyName').textContent,
        reportDate: new Date().toISOString(),
        timeInBusiness: `${gameState.currentYear} years, ${getDisplayMonth()} months`,
        
        // Financial metrics
        financial: {
            totalRevenue: gameState.totalRevenue,
            monthlyRevenue: gameState.monthlyRevenue,
            monthlyBurn: gameState.monthlyBurn,
            netIncome: gameState.monthlyRevenue - gameState.monthlyBurn,
            currentRunway: gameState.runway,
            runwayMonths: gameState.runway > 0 ? Math.floor(gameState.runway / Math.max(gameState.monthlyBurn - gameState.monthlyRevenue, 1)) : 0
        },
        
        // Customer metrics
        customer: {
            totalCustomers: gameState.customers,
            averageRevenuePerCustomer: gameState.customers > 0 ? (gameState.monthlyRevenue / gameState.customers) : 0,
            engagement: gameState.engagement,
            growth: gameState.growth
        },
        
        // Business metrics
        business: {
            teamSize: gameState.teamSize,
            confidence: gameState.confidence,
            credibility: gameState.credibility,
            reach: gameState.reach,
            founderStress: gameState.stress,
            founderWellbeing: getStressLevel(gameState.stress).label,
            decisionsCount: gameState.selectedCards.filter(card => card.category !== 'outcome').length,
            decisionRate: gameState.cardsGenerated > 0 ? (gameState.selectedCards.filter(card => card.category !== 'outcome').length / gameState.cardsGenerated) * 100 : 0
        },
        
        // Full selections for context
        businessDecisions: gameState.selectedCards,
        
        // Generated at
        exportedAt: new Date().toISOString()
    };
    
    const dataStr = JSON.stringify(reportData, null, 2);
    const dataBlob = new Blob([dataStr], {type: 'application/json'});
    
    const link = document.createElement('a');
    link.href = URL.createObjectURL(dataBlob);
    link.download = `${reportData.companyName.replace(/\s+/g, '_')}_company_metrics_report.json`;
    link.click();
    
    // Also log to console for debugging
    console.log('Company Metrics Report:', reportData);
    
    // Show a brief success message
    const originalText = event.target.textContent;
    event.target.textContent = 'Exported! ✓';
    event.target.style.background = '#10b981';
    
    setTimeout(() => {
        event.target.textContent = originalText;
        event.target.style.background = '';
    }, 2000);
}

// Initialize company metrics modal functionality
function initializeCompanyMetricsModal() {
    const companyNameDiv = document.getElementById('companyName');
    
    if (companyNameDiv) {
        // Make it look clickable
        companyNameDiv.style.cursor = 'pointer';
        companyNameDiv.style.transition = 'all 0.2s ease';
        
        // Add hover effect
        companyNameDiv.addEventListener('mouseenter', function() {
            this.style.transform = 'scale(1.05)';
            this.style.boxShadow = '0 4px 12px rgba(30, 58, 138, 0.3)';
        });
        
        companyNameDiv.addEventListener('mouseleave', function() {
            this.style.transform = 'scale(1)';
            this.style.boxShadow = '';
        });
        
        // Add click event (toggle: opens, or closes if already open)
        companyNameDiv.addEventListener('click', toggleCompanyMetricsModal);
    }
    
    // Modal event listeners for clicking outside to close
    document.addEventListener('click', (e) => {
        const modal = document.getElementById('companyMetricsModal');
        if (modal && e.target === modal) {
            closeCompanyMetricsModal();
        }
    });
    
    // Escape key to close modal
    document.addEventListener('keydown', (e) => {
        if (e.key === 'Escape') {
            closeCompanyMetricsModal();
        }
    });
}
