// NEW FUNCTIONS FOR SELECTIONS VIEW
function createSelectionsModal() {
    const modal = document.createElement('div');
    modal.className = 'selections-modal';
    modal.id = 'selectionsModal';
    modal.setAttribute('role', 'dialog');
    modal.setAttribute('aria-modal', 'true');
    modal.setAttribute('aria-labelledby', 'selectionsTitle');

    modal.innerHTML = `
        <div class="selections-modal-content">
            <div class="selections-header">
                <h2 id="selectionsTitle">📋 Your Selections</h2>
                <button type="button" class="close-modal" onclick="closeSelectionsModal()" aria-label="Close selections">&times;</button>
            </div>
            <div class="selections-body" id="selectionsBody">
                <!-- Content will be populated by showSelections() -->
            </div>
            <div class="selections-footer">
                <button type="button" class="btn btn-clear" onclick="clearAllSelections()">Clear All</button>
                <button type="button" class="btn btn-export" onclick="exportSelections()">Export Plan</button>
            </div>
        </div>
    `;

    document.body.appendChild(modal);
}

function showSelectionsModal() {
    let modal = document.getElementById('selectionsModal');
    
    // Create modal if it doesn't exist
    if (!modal) {
        createSelectionsModal();
        modal = document.getElementById('selectionsModal');
    }
    
    // Populate with current selections
    populateSelections();

    // Show modal. On desktop it's a pinned side panel, not a focus-trapping
    // overlay, so the player can keep driving the cards with the keyboard.
    openDialog(modal, { trap: !window.matchMedia('(min-width: 1330px)').matches });
}

function closeSelectionsModal() {
    const modal = document.getElementById('selectionsModal');
    if (modal && modal.style.display === 'flex') {
        closeDialog(modal);
    }
}

function toggleSelectionsModal() {
    const modal = document.getElementById('selectionsModal');
    if (modal && modal.style.display === 'flex') {
        closeSelectionsModal();
    } else {
        showSelectionsModal();
    }
}

// Tracks how many selections were shown in the previous render, so we can tell
// when a new card was just added (and animate only that one).
let lastSelectionCount = 0;

function populateSelections() {
    const selectionsBody = document.getElementById('selectionsBody');
    
    if (gameState.selectedCards.length === 0) {
        lastSelectionCount = 0;
        if (selectionsChart) { selectionsChart.destroy(); selectionsChart = null; }
        selectionsBody.innerHTML = `
            <div class="no-selections">
                <div class="no-selections-icon">🎯</div>
                <h3>No selections yet</h3>
                <p>Start building your startup by adding cards!</p>
            </div>
        `;
        return;
    }
    
    const categoryEmojis = {
        validation: "🎯",
        team: "🤜🤛",
        product: "⚡",
        marketing: "📈",
        business: "💼",
        revenue: "💰",
        outcome: "✨",
        esg: "🌐"
    };
    
    // Cumulative one-time spend across every decision (costs are stored negative)
    const totalInvested = gameState.selectedCards.reduce(
        (sum, c) => sum + Math.abs(c.impact && c.impact.cost ? c.impact.cost : 0), 0);
    const formatInvested = (abs) => {
        if (abs >= 1000000) return '$' + (abs / 1000000).toFixed(1).replace('.0', '') + 'M';
        if (abs >= 1000) return '$' + (abs / 1000).toFixed(1).replace('.0', '') + 'k';
        return '$' + abs;
    };

    let html = `
        <div class="selections-summary">
            <div class="summary-stats">
                <div class="summary-stat">
                    <span class="summary-value">${gameState.selectedCards.length}</span>
                    <span class="summary-label">Total Selections</span>
                </div>
                <div class="summary-stat">
                    <span class="summary-value">${formatInvested(totalInvested)}</span>
                    <span class="summary-label">Total Invested</span>
                </div>
                <div class="summary-stat">
                    <span class="summary-value">${gameState.timeToMVP > 0 ? Math.round(gameState.timeToMVP) + 'mo' : '—'}</span>
                    <span class="summary-label">Time to MVP</span>
                </div>
            </div>
            <div class="selections-chart"><canvas id="selectionsChart" role="img" aria-label="Bar chart of selections by category"></canvas></div>
        </div>
    `;
    
    // Only animate when the list actually grew (a card was added) — not on every
    // repopulate (open / remove / clear). The newest card sits at the last index.
    const justAdded = gameState.selectedCards.length > lastSelectionCount;
    const newestIndex = gameState.selectedCards.length - 1;

    // Newest selection on top: render in reverse, but keep the real index in
    // gameState.selectedCards so removeSelection() targets the right card.
    gameState.selectedCards.map((card, i) => [card, i]).reverse().forEach(([card, globalIndex]) => {
        const category = card.category;
        const isRemovable = category !== 'outcome'; // Don't allow removing outcome/opportunity cards
        const isNew = justAdded && globalIndex === newestIndex;
        
        // Use the stored calendar date or fall back to relative time
        const timeDisplay = card.selectedAt || card.relativeTime || 'Time not recorded';
        const detailTime = card.relativeTime ? `(${card.relativeTime})` : '';
        
        html += `
            <div class="selection-item ${category}${isNew ? ' is-new' : ''}">
                <div class="selection-content">
                    <div class="timeline-item-info">
                        <div class="selection-title">${card.title}</div>
                        <a href="javascript:learnMore('${card.category}')" aria-label="Learn more about ${card.category} (opens in new tab)">
                            <div class="card-type selection-timeline">${card.category}&nbsp; ${categoryEmojis[category]}</div>
                        </a>
                    </div>
                    <div class="selection-time">
                        <div class="selection-date">${timeDisplay}</div>&nbsp;
                        ${detailTime ? `<div class="selection-relative-time">${detailTime}</div>` : ''}
                    </div>
                </div>
                ${isRemovable ? `
                    <button type="button" class="remove-selection" onclick="removeSelection(${globalIndex})" title="Remove this selection" aria-label="Remove ${card.title}">
                        &times;
                    </button>
                ` : `
                    <div class="remove-selection" style="background: #f1f5f9; color: #94a3b8; cursor: not-allowed;" title="Outcome cards cannot be removed" aria-hidden="true">
                        🔒
                    </div>
                `}
            </div>
        `;
    });
    
    selectionsBody.innerHTML = html;
    lastSelectionCount = gameState.selectedCards.length;
    // Draw the by-category bar chart now that the canvas exists in the DOM.
    renderSelectionsChart();
    // Newest selection is on top now, so keep the view at the top.
    selectionsBody.scrollTop = 0;
}

// Live Chart instance for the selections-by-category bar chart, so we can tear it
// down and rebuild whenever the modal body's innerHTML is regenerated.
let selectionsChart = null;

// Display order + colors for each category, matching the card border colors used
// across the app (see css/selections-modal.css and css/biz-sim.css).
const SELECTION_CATEGORY_META = [
    { key: 'validation', label: 'Validation', color: '#059669' },
    { key: 'team',       label: 'Team',       color: '#dc2626' },
    { key: 'product',    label: 'Product',    color: '#7c3aed' },
    { key: 'marketing',  label: 'Marketing',  color: '#ea580c' },
    { key: 'business',   label: 'Business',   color: '#0369a1' },
    { key: 'revenue',    label: 'Revenue',    color: '#d1ad3a' },
    { key: 'esg',        label: 'ESG',        color: '#95d609' },
    { key: 'outcome',    label: 'Outcome',    color: '#64748b' }
];

function renderSelectionsChart() {
    const canvas = document.getElementById('selectionsChart');
    if (!canvas || typeof Chart === 'undefined') return; // CDN failed — skip gracefully

    if (selectionsChart) {
        selectionsChart.destroy();
        selectionsChart = null;
    }

    // Count selections per category, then keep only categories the player has used.
    const counts = {};
    gameState.selectedCards.forEach(c => { counts[c.category] = (counts[c.category] || 0) + 1; });
    const present = SELECTION_CATEGORY_META.filter(m => counts[m.key]);

    selectionsChart = new Chart(canvas.getContext('2d'), {
        type: 'bar',
        data: {
            labels: present.map(m => m.label),
            datasets: [{
                label: 'Selections',
                data: present.map(m => counts[m.key]),
                backgroundColor: present.map(m => m.color),
                borderRadius: 6,
                maxBarThickness: 48
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            animation: { duration: 250, easing: 'easeOutQuart' },
            plugins: {
                tooltip: { enabled: true },
                // Single-dataset bar chart, so build one legend entry per category
                // (colored square + label). Mirrors the company-modal charts' top legend.
                legend: {
                    position: 'top',
                    labels: {
                        boxWidth: 12,
                        boxHeight: 12,
                        font: { size: 11 },
                        generateLabels: (chart) => {
                            const ds = chart.data.datasets[0];
                            return chart.data.labels.map((text, i) => ({
                                text,
                                fillStyle: ds.backgroundColor[i],
                                strokeStyle: ds.backgroundColor[i],
                                hidden: !chart.getDataVisibility(i),
                                index: i
                            }));
                        }
                    },
                    onClick: (e, legendItem, legend) => {
                        legend.chart.toggleDataVisibility(legendItem.index);
                        legend.chart.update();
                    }
                }
            },
            scales: {
                // The legend identifies each bar, so the x-axis ticks would just
                // duplicate it — hide them for a cleaner look.
                x: { grid: { display: false }, ticks: { display: false } },
                y: { beginAtZero: true, ticks: { font: { size: 10 }, precision: 0 } }
            }
        }
    });
}

// FIXED: Use global index instead of category-based index
function removeSelection(globalIndex) {
    // Validate index
    if (globalIndex < 0 || globalIndex >= gameState.selectedCards.length) {
        console.error('Invalid selection index:', globalIndex);
        return;
    }
    
    const card = gameState.selectedCards[globalIndex];
    
    // Don't allow removing outcome/opportunity cards
    if (card.category === 'outcome') {
        showAlertDialog({
            icon: '🔒',
            title: 'Can\'t remove this card',
            message: 'Outcome cards represent permanent outcomes of your decisions and can\'t be removed.'
        });
        return;
    }
    
    // Remove the card at the specific global index
    gameState.selectedCards.splice(globalIndex, 1);
    
    // Recalculate game stats
    recalculateGameStats();
    
    // Update the modal content
    populateSelections();
    
    // Update button text
    updateSelectionsButtonText();
}

function clearAllSelections() {
    showConfirmDialog({
        tone: 'danger',
        icon: '🗑️',
        title: 'Clear all selections?',
        note: 'This removes every decision from your timeline and cannot be undone. Outcome cards will remain, as they represent permanent outcomes.',
        cancelLabel: 'Keep',
        confirmLabel: 'Clear all',
        onConfirm: () => {
            // Only remove cards that aren't outcomes
            const hadOutcomes = gameState.selectedCards.some(card => card.category === 'outcome');
            gameState.selectedCards = gameState.selectedCards.filter(card => card.category === 'outcome');

            recalculateGameStats();
            populateSelections();
            updateSelectionsButtonText();

            if (hadOutcomes) {
                showAlertDialog({
                    icon: 'ⓘ',
                    title: 'Selections cleared',
                    message: 'Outcome cards remain in your timeline, as they represent permanent outcomes of your decisions.'
                });
            }
        }
    });
}

// Rebuilds gameState from the remaining selections after a removal/clear.
// Mirrors updateGameStats (biz-sim.js) but uses FIXED category bonuses instead of
// random rolls, so removing a card doesn't re-roll the rest of the run.
function recalculateGameStats() {
    // Reset to founding baseline (must match updateGameStats' starting values)
    gameState.teamSize = 1;
    gameState.timeToMVP = 0; // 0 = MVP not launched yet (recomputed during replay below)
    gameState.monthlyBurn = 1000;
    gameState.monthlyRevenue = 0;
    gameState.oneTimeRevenue = 0;
    gameState.totalRevenue = 0;
    gameState.runway = 100000;
    gameState.revenueStreams = [];
    gameState.currentMonth = 1;
    gameState.currentYear = 1;
    gameState.customers = 0;
    gameState.growth = 0;
    gameState.engagement = 0;
    gameState.confidence = 0;
    gameState.credibility = 0;
    gameState.reach = 0;
    gameState.stress = 0;

    // Fixed (deterministic) version of the category bonuses in updateGameStats
    const categoryBonus = {
        validation: () => { gameState.confidence += 7; gameState.customers += 15; },
        team:       () => { gameState.credibility += 6; gameState.growth += 4; },
        product:    () => { gameState.engagement += 12; gameState.customers += 37; },
        marketing:  () => { gameState.reach += 17; gameState.growth += 10; gameState.customers += 75; },
        business:   () => { gameState.confidence += 9; gameState.credibility += 7; },
        revenue:    () => { gameState.customers += 22; gameState.confidence += 12; }
    };

    // MVP launches the month the player first holds both a validation and a
    // product card (see checkMVPLaunch). Recompute that month during the replay so
    // removing an unrelated card doesn't move it — and so removing the last
    // validation/product card un-launches the MVP (timeToMVP stays 0).
    let seenValidation = false;
    let seenProduct = false;

    // Replay remaining cards in order so revenue-stream expiry and burn line up.
    gameState.selectedCards.forEach(card => {
        const impact = card.impact || {};
        const prevMonth = gameState.currentMonth;

        if (impact.time) {
            gameState.currentMonth += Math.abs(impact.time);
        }
        const monthsPassed = gameState.currentMonth - prevMonth;

        if (card.category === 'validation') seenValidation = true;
        if (card.category === 'product') seenProduct = true;
        if (seenValidation && seenProduct && gameState.timeToMVP === 0) {
            gameState.timeToMVP = gameState.currentMonth;
        }

        if (card.category === 'team') {
            gameState.teamSize++;
            gameState.monthlyBurn += (card.salary || 0) / 12;
        }

        // Financials (positive cost = spent, negative = saved)
        if (impact.cost) gameState.runway -= impact.cost;
        if (impact.oneTimeRevenue) {
            gameState.runway += impact.oneTimeRevenue;
            gameState.totalRevenue += impact.oneTimeRevenue;
        }
        if (impact.monthlyRevenue) {
            gameState.revenueStreams.push({
                amount: impact.monthlyRevenue,
                monthsRemaining: impact.recurringPayTime || Infinity
            });
        }

        // Direct metric impacts + folded modifiers
        if (impact.customers) gameState.customers += impact.customers;
        if (impact.growth) gameState.growth += impact.growth;
        if (impact.engagement) gameState.engagement += impact.engagement;
        if (impact.confidence) gameState.confidence += impact.confidence;
        if (impact.credibility) gameState.credibility += impact.credibility;
        if (impact.reach) gameState.reach += impact.reach;
        if (impact.retention) gameState.engagement += Math.floor(impact.retention * 0.5);
        if (impact.quality) gameState.confidence += Math.floor(impact.quality * 0.3);
        if (impact.scalability) gameState.reach += Math.floor(impact.scalability * 0.4);
        if (impact.stress) gameState.stress += impact.stress;

        if (categoryBonus[card.category]) categoryBonus[card.category]();

        // Accrue recurring revenue + burn for the months that passed
        let revenueThisPeriod = 0;
        for (let i = 0; i < monthsPassed; i++) {
            for (const stream of gameState.revenueStreams) {
                if (stream.monthsRemaining > 0) {
                    revenueThisPeriod += stream.amount;
                    stream.monthsRemaining -= 1;
                }
            }
        }
        gameState.revenueStreams = gameState.revenueStreams.filter(s => s.monthsRemaining > 0);
        if (monthsPassed > 0) {
            gameState.runway -= gameState.monthlyBurn * monthsPassed;
            gameState.runway += revenueThisPeriod;
            gameState.totalRevenue += revenueThisPeriod;
        }
    });

    // Current recurring revenue = sum of still-active streams
    gameState.monthlyRevenue = gameState.revenueStreams.reduce((sum, s) => sum + s.amount, 0);
    gameState.currentYear = Math.floor((gameState.currentMonth - 1) / 12) + 1;

    // Keep the MVP-launched flag in sync with the replay: if the combo no longer
    // exists, clear it so the launch card can fire again later.
    if (!gameState.milestonesHit) gameState.milestonesHit = {};
    gameState.milestonesHit.mvpLaunched = gameState.timeToMVP > 0;

    // Estimate customers from revenue if needed
    if (gameState.customers < 10 && gameState.monthlyRevenue > 1000) {
        gameState.customers = Math.floor(gameState.monthlyRevenue / 100);
    }

    // Cap all percentage-based metrics at 100
    gameState.growth = Math.min(100, Math.max(0, gameState.growth));
    gameState.engagement = Math.min(100, Math.max(0, gameState.engagement));
    gameState.confidence = Math.min(100, Math.max(0, gameState.confidence));
    gameState.credibility = Math.min(100, Math.max(0, gameState.credibility));
    gameState.reach = Math.min(100, Math.max(0, gameState.reach));
    gameState.stress = Math.min(100, Math.max(0, gameState.stress));
    gameState.customers = Math.max(0, gameState.customers);

    // FIXED: Update UI using the correct element IDs and safe checks
    const teamSizeElement = document.getElementById('teamSize');
    const currentMonthElement = document.getElementById('currentMonth');  
    const runwayElement = document.getElementById('runway');
    const revenueElement = document.getElementById('revenue');
    
    if (teamSizeElement) {
        teamSizeElement.textContent = gameState.teamSize;
    }
    
    if (currentMonthElement) {
        // Update month display with year tracking (matching the format in updateUI)
        const displayMonth = getDisplayMonth();
        if (gameState.currentYear > 1) {
            currentMonthElement.textContent = `Y${gameState.currentYear} M${displayMonth}`;
        } else {
            currentMonthElement.textContent = `M${displayMonth}`;
        }
    }
    
    if (runwayElement) {
        // Format runway display (matching the format in updateUI)
        let runwayDisplay;
        if (gameState.runway >= 1000000) {
            runwayDisplay = '$' + (gameState.runway / 1000000).toFixed(1) + 'M';
        } else if (gameState.runway >= 1000) {
            runwayDisplay = '$' + (gameState.runway / 1000).toFixed(0) + 'K';
        } else if (gameState.runway >= 0) {
            runwayDisplay = '$' + gameState.runway.toFixed(0);
        } else {
            const absRunway = Math.abs(gameState.runway);
            if (absRunway >= 1000000) {
                runwayDisplay = '-$' + (absRunway / 1000000).toFixed(1) + 'M';
            } else if (absRunway >= 1000) {
                runwayDisplay = '-$' + (absRunway / 1000).toFixed(0) + 'K';
            } else {
                runwayDisplay = '-$' + absRunway.toFixed(0);
            }
        }
        runwayElement.textContent = runwayDisplay;
    }
    
    if (revenueElement) {
        revenueElement.textContent = '$' + (gameState.monthlyRevenue / 1000).toFixed(1) + 'k/mo';
    }
    
    // Also call the main updateUI function if it exists (this will handle any other UI updates)
    if (typeof updateUI === 'function') {
        updateUI();
    }
}

function exportSelections() {
    const exportData = {
        companyName: document.getElementById('companyName').textContent,
        stats: {
            teamSize: gameState.teamSize,
            timeToMVP: gameState.timeToMVP,
            // Total annual salary across all hired (team) cards, computed fresh
            cost: gameState.selectedCards.reduce(
                (sum, c) => sum + (c.category === 'team' ? (c.salary || 0) : 0), 0)
        },
        selections: gameState.selectedCards,
        exportedAt: new Date().toISOString()
    };
    
    const dataStr = JSON.stringify(exportData, null, 2);
    const dataBlob = new Blob([dataStr], {type: 'application/json'});
    
    const link = document.createElement('a');
    link.href = URL.createObjectURL(dataBlob);
    link.download = `${exportData.companyName.replace(/\s+/g, '_')}_business_plan.json`;
    link.click();
    
    // Also show a summary in console for debugging
    console.log('Startup Plan Export:', exportData);
}

