// Map a cumulative stress score (0-100) to a founder wellbeing level for display.
function getStressLevel(stress) {
    if (stress >= 80) return { label: "Burnt Out", emoji: "🔥", class: "negative" };
    if (stress >= 60) return { label: "Overwhelmed", emoji: "😣", class: "negative" };
    if (stress >= 40) return { label: "Stressed", emoji: "😰", class: "warning" };
    if (stress >= 20) return { label: "Steady", emoji: "🙂", class: "positive" };
    return { label: "Energized", emoji: "😌", class: "positive" };
}

// Function to calculate the current game date based on months elapsed
function getCurrentGameDate() {
    const foundedDate = new Date(gameState.founded);
    const monthsElapsed = gameState.currentMonth - 1;
    // Add months to the founded date
    const currentGameDate = new Date(foundedDate);
    currentGameDate.setMonth(currentGameDate.getMonth() + monthsElapsed);
    
    return currentGameDate;
}

// Function to format game date for display
    function formatGameDate(date, includeTime = false) {
        const options = {
            year: 'numeric',
            month: 'short',
            day: 'numeric'
        };
        
        if (includeTime) {
            options.hour = '2-digit';
            options.minute = '2-digit';
        }
        return date.toLocaleDateString('en-US', options);
    }

// Function to get a relative time description
    function getRelativeTimeDescription(gameDate, foundedDate) {
        const monthsElapsed = Math.round((gameDate - foundedDate) / (1000 * 60 * 60 * 24 * 30.44)); // Average days per month
        
        if (monthsElapsed === 0) {
            return "Founding";
        } else if (monthsElapsed === 1) {
            return "1 month in";
        } else if (monthsElapsed < 12) {
            return `${monthsElapsed} months in`;
        } else {
            const years = Math.floor(monthsElapsed / 12);
            const remainingMonths = monthsElapsed % 12;
            if (remainingMonths === 0) {
                return years === 1 ? "1 year in" : `${years} years in`;
            } else {
                return `${years}y ${remainingMonths}m in`;
            }
        }
    }

// Month-within-year for display, rounded to one decimal. Ramp times can be
// fractional (e.g. a scaled hire at 2.6mo), and accumulating them drifts in
// floating point — without rounding the header would read "M4.7999999". Shared
// by the company and selections modals so every month readout matches.
    function getDisplayMonth() {
        return Math.round((((gameState.currentMonth - 1) % 12) + 1) * 10) / 10;
    }

