// Enhanced game state updates with proper time and financial tracking
// Advance organic customer growth by one in-game month: acquisition (reach + referrals)
// minus churn (low engagement / high stress), tapered by market saturation. Mutates
// gameState.customers. See the CUSTOMER_* constants for tuning.
function advanceCustomers(dt = 1) {
    const reachF = gameState.reach / 100, growthF = gameState.growth / 100;
    const engF = gameState.engagement / 100, stressF = gameState.stress / 100;
    const saturation = 1 - Math.min(1, gameState.customers / CUSTOMER_MARKET_CAP);
    // Pricing pressure: above fair price, fewer sign up and more churn; below it, a boost.
    const overFair = gameState.pricePerCustomer - CUSTOMER_FAIR_PRICE;
    const acqPriceMult = Math.max(0.1, Math.min(1.5, 1 - overFair / CUSTOMER_PRICE_ACQ_SENS));
    const churnPriceAdd = Math.max(0, overFair) * CUSTOMER_PRICE_CHURN;
    const acquisition = (CUSTOMER_ACQ_BASE * reachF * (0.3 + growthF)
                         + CUSTOMER_REF_RATE * gameState.customers * engF) * saturation * acqPriceMult * dt;
    const churn = gameState.customers * (CUSTOMER_CHURN_BASE * (1 - engF)
                         + CUSTOMER_CHURN_STRESS * stressF + churnPriceAdd) * dt;
    gameState.customers = Math.max(0, Math.round(gameState.customers + acquisition - churn));
}

// Current monthly revenue rate = per-customer subscriptions + active discrete streams.
function recomputeMonthlyRevenue() {
    const subs = gameState.customers * gameState.pricePerCustomer;
    const streams = gameState.revenueStreams.reduce((sum, s) => sum + s.amount, 0);
    gameState.monthlyRevenue = Math.round(subs + streams);
}

// Reflect the current price in the bottom-nav stepper.
function updatePriceDisplay() {
    const el = document.getElementById('priceValue');
    if (el) el.textContent = '$' + gameState.pricePerCustomer;
}

// Set the subscription price (clamped ≥ 0). Price is a FORWARD policy: it must not
// retroactively rewrite already-earned revenue or the current rate. So we only store it
// and update the stepper label — the new price first takes effect on the next decision,
// when updateGameStats() accrues that month and recomputes monthlyRevenue.
function setPrice(newPrice) {
    gameState.pricePerCustomer = Math.max(0, newPrice);
    updatePriceDisplay();
    showPriceProjection();
    // The price is forward-looking policy but still part of the saved run.
    if (typeof saveCurrentGame === 'function') saveCurrentGame();
}

// Briefly float a projection toast showing the estimated next-month net income at the
// current price + customer base. Purely a hint — it does NOT change actual revenue/runway.
let priceProjectionTimer = null;
function showPriceProjection() {
    const el = document.getElementById('priceProjection');
    if (!el) return;
    const projRevenue = gameState.customers * gameState.pricePerCustomer
                        + gameState.revenueStreams.reduce((sum, s) => sum + s.amount, 0);
    const projNet = Math.round(projRevenue - gameState.monthlyBurn);
    const sign = projNet >= 0 ? '+' : '−';
    el.textContent = `Next mo ≈ ${sign}$${Math.abs(projNet).toLocaleString()}/mo`;
    el.classList.toggle('positive', projNet >= 0);
    el.classList.toggle('negative', projNet < 0);
    el.classList.add('is-visible');
    clearTimeout(priceProjectionTimer);
    priceProjectionTimer = setTimeout(() => el.classList.remove('is-visible'), 2500);
}

// Bottom-nav − / + handlers.
function changePrice(delta) {
    setPrice(gameState.pricePerCustomer + delta);
}

