        if (!im) return;
        if (im.customers) gameState.customers += sign * im.customers;
        if (im.growth) gameState.growth += sign * im.growth;
        if (im.engagement) gameState.engagement += sign * im.engagement;
        if (im.confidence) gameState.confidence += sign * im.confidence;
        if (im.credibility) gameState.credibility += sign * im.credibility;
        if (im.reach) gameState.reach += sign * im.reach;
        if (im.retention) gameState.engagement += sign * Math.floor(im.retention * 0.5);
        if (im.quality) gameState.confidence += sign * Math.floor(im.quality * 0.3);
        if (im.scalability) gameState.reach += sign * Math.floor(im.scalability * 0.4);
