            const dt = Math.min(1, remaining);
            // Metrics erode without upkeep (scaled to the step) so they can't sit at 100.
            // Engagement slips first so neglect feeds churn the same step.
            gameState.engagement  = Math.max(0, gameState.engagement - 2 * dt);
            gameState.reach       = Math.max(0, gameState.reach       * (1 - REACH_DECAY * dt));
            gameState.growth      = Math.max(0, gameState.growth      * (1 - GROWTH_DECAY * dt));
            gameState.confidence  = Math.max(0, gameState.confidence  * (1 - CONFIDENCE_DECAY * dt));
            gameState.credibility = Math.max(0, gameState.credibility * (1 - CREDIBILITY_DECAY * dt));
