// Enhanced outcome checking with better performance
function checkForOutcomes() {
    const recentSelections = gameState.selectedCards.slice(-3);
    const categoryCount = gameState.selectedCards.reduce((acc, card) => {
        acc[card.category] = (acc[card.category] || 0) + 1;
        return acc;
    }, {});
    
    // Check for various triggers with improved logic
    const triggers = [
        { condition: !categoryCount.validation && gameState.selectedCards.length > 5, outcome: "no_validation" },
        { condition: gameState.teamSize === 1 && gameState.selectedCards.length > 8, outcome: "solo_founder" },
        { condition: gameState.runway < 10000 && gameState.monthlyRevenue < 2000 && gameState.selectedCards.length > 6, outcome: "high_budget" },
        { condition: !categoryCount.marketing && gameState.selectedCards.length > 6, outcome: "no_marketing" },
        { condition: gameState.selectedCards.length > 25 && gameState.customers < 40 && gameState.teamSize > 5, outcome: "employee_quit" },
        { condition: (categoryCount.product || 0) >= 2 && gameState.customers > 600 && !gameState.selectedCards.some(c => c.title === "DevOps Engineer"), outcome: "no_devops" }
    ];
    
    triggers.forEach(trigger => {
        if (trigger.condition) {
            const outcome = outcomeCards.challenges.find(c => c.trigger === trigger.outcome);
            if (outcome) queueOutcomeCard(outcome);
        }
        // is this the right place to do this?
        if (trigger.condition && trigger.outcome === "employee_quit") {
            removeMostJuniorEmployee(); // reverses metrics/burn and updates teamSize
        }

    });
    
    // Check for positive outcomes
    recentSelections.forEach(selection => {
        const positiveOutcome = outcomeCards.positive.find(outcome => 
            outcome.trigger === selection.title.toLowerCase().replace(/\s+/g, '_') ||
            outcome.trigger === selection.category
        );
        
        if (positiveOutcome && Math.random() > 0.7) {
            queueOutcomeCard(positiveOutcome);
        }
    });
    
    // Revenue-based opportunities
        if (gameState.monthlyRevenue > 5000 && gameState.growth > 0) {
            const opportunity = outcomeCards.opportunities.find(o => o.trigger === "strong_growth");
            if (opportunity && Math.random() > 0.6) {
                queueOutcomeCard(opportunity);
            }
        }
        
        if (gameState.monthlyRevenue > 300000 && gameState.selectedCards.length > 15 && gameState.customers > 10) {
            const opportunity = outcomeCards.opportunities.find(o => o.trigger === "proven_model");
            if (opportunity && Math.random() > 0.75) {
                queueOutcomeCard(opportunity);
            }
        }
        
        if (gameState.monthlyRevenue > 50000 && gameState.selectedCards.length > 25) {
            const opportunity = outcomeCards.opportunities.find(o => o.trigger === "b2c_struggles");
            if (opportunity && Math.random() > 0.4) {
                queueOutcomeCard(opportunity);
            }
        }

        // Selection-driven opportunity: Business Travel can open a partnership deal (fires once)
        if (gameState.selectedCards.some(c => c.title === "Business Travel") && !gameState.travelOpportunityFired && Math.random() > 0.5) {
            const opportunity = outcomeCards.opportunities.find(o => o.trigger === "business_travel");
            if (opportunity) {
                queueOutcomeCard(opportunity);
                gameState.travelOpportunityFired = true;
            }
        }

        // Selection + satisfaction driven positive: happy users + strong support => brand loyalty (fires once)
        if (gameState.engagement > 50 &&
            gameState.selectedCards.some(c => c.title === "Customer Success Manager") &&
            !gameState.brandLoyaltyFired && Math.random() > 0.5) {
            const outcome = outcomeCards.positive.find(o => o.trigger === "brand_loyalty");
            if (outcome) {
                queueOutcomeCard(outcome);
                gameState.brandLoyaltyFired = true;
            }
        }

        // Visibility-driven challenge: high reach makes you a target for an online mob (fires once)
        if (gameState.reach > 60 && !gameState.pileOnFired && Math.random() > 0.5) {
            const outcome = outcomeCards.challenges.find(c => c.trigger === "founder_pile_on");
            if (outcome) {
                queueOutcomeCard(outcome);
                gameState.pileOnFired = true;
            }
        }

        // Overhype challenge: heavy marketing with no product to back it => public backlash (fires once)
        if ((categoryCount.marketing || 0) >= 3 && (categoryCount.product || 0) === 0 && !gameState.backlashFired && Math.random() > 0.5) {
            const outcome = outcomeCards.challenges.find(c => c.trigger === "public_backlash");
            if (outcome) {
                queueOutcomeCard(outcome);
                gameState.backlashFired = true;
            }
        }

        // Complexity challenge: lots of features built on little validation => product too hard to use (fires once)
        if ((categoryCount.product || 0) >= 3 && (categoryCount.validation || 0) <= 1 && !gameState.onboardingFired && Math.random() > 0.5) {
            const outcome = outcomeCards.challenges.find(c => c.trigger === "complex_onboarding");
            if (outcome) {
                queueOutcomeCard(outcome);
                gameState.onboardingFired = true;
            }
        }

        // Morale wall: deep into the journey with weak traction => the long haul gets demoralizing (fires once)
        if (gameState.currentMonth > 18 && gameState.monthlyRevenue < 3000 && gameState.customers < 100 && !gameState.longHaulFired && Math.random() > 0.5) {
            const outcome = outcomeCards.challenges.find(c => c.trigger === "long_haul");
            if (outcome) {
                queueOutcomeCard(outcome);
                gameState.longHaulFired = true;
            }
        }

        // Wellbeing fork: when the founder is overwhelmed, offer a real break vs. pushing on
        if (gameState.stress > 60) {
            const opportunity = outcomeCards.opportunities.find(o => o.trigger === "high_stress");
            if (opportunity && Math.random() > 0.6) {
                queueOutcomeCard(opportunity);
            }
        }
    }

    let outcomeQueue = [];

    function queueOutcomeCard(outcome) {
        if (!outcomeQueue.find(c => c.title === outcome.title)) {
            outcomeQueue.push(outcome);
        }
    }

    // How much of the cash on hand an offer credits. Cash is hard value, so it's
    // added OUTSIDE the health/luck multiplier (a bad luck roll can't discount the
    // bank balance) — but only partially, since the founder never walks with the
    // whole treasury. This keeps the *business* fundamentals, not the cash pile,
    // as what makes an offer good or bad.
    const ACQ_CASH_CREDIT = 0.6;

    // Value the company the way an acquirer roughly would. Enterprise value — a
    // revenue multiple (richer for fast growers) plus strategic value per customer
    // — is tilted by overall health (reputation, reach, confidence; founder burnout
    // drags it down) and a per-acquirer luck swing so some offers come in low and
    // others high. A fraction of the cash balance is then added on top at face.
    function computeAcquisitionOffer() {
        const f01 = (v) => Math.max(0, Math.min(1, v));

        const arr = Math.max(0, gameState.monthlyRevenue) * 12;
        const growthF = f01(gameState.growth / 100);
        const revenueMultiple = 3 + growthF * 5; // 3x–8x ARR

        const engagementF = f01(gameState.engagement / 100);
        const customerValue = gameState.customers * (50 + engagementF * 250); // $50–$300 ea.

        const enterpriseValue = arr * revenueMultiple + customerValue;

        const health = f01((gameState.credibility + gameState.reach + gameState.confidence) / 300);
        const stressDrag = f01(gameState.stress / 100);
        const healthFactor = 0.7 + health * 0.6 - stressDrag * 0.3; // ~0.4–1.3

        const luck = 0.75 + Math.random() * 0.5; // ±25% per-acquirer swing

        const cash = Math.max(0, gameState.runway);
        const cashCredit = cash * ACQ_CASH_CREDIT;

        // Floor keeps an early-but-promising company from getting an insulting bid.
        const offerRaw = Math.max(enterpriseValue * healthFactor * luck + cashCredit, 250000);
        return roundOffer(offerRaw);
    }

    // Round to a figure that reads like a real offer ($50k / $100k / $500k steps).
    function roundOffer(v) {
        if (v < 1000000)  return Math.round(v / 50000) * 50000;
        if (v < 10000000) return Math.round(v / 100000) * 100000;
        return Math.round(v / 500000) * 500000;
    }

    // Clone the static acquisition template with a freshly computed price baked
    // into both the description and the "Accept Offer" choice (salePrice drives
    // the exit proceeds; oneTimeRevenue keeps the impact consistent).
    function buildAcquisitionOffer(template) {
        const offer = computeAcquisitionOffer();
        const card = Object.assign({}, template);
        card.title = `Acquisition Offer — ${formatMoney(offer)}`;
        card.description = `A larger company wants to buy your startup for ${formatMoney(offer)}. Take the exit or keep building?`;
        card.choices = template.choices.map(choice =>
            choice.exit
                ? Object.assign({}, choice, {
                    salePrice: offer,
                    impact: Object.assign({}, choice.impact, { oneTimeRevenue: offer })
                })
                : choice
        );
        return card;
    }

    function generateOutcomeCard() {
        if (outcomeQueue.length === 0) return null;

        // Priority cards (e.g. the MVP launch capstone) jump ahead of normal outcomes.
        const priorityIdx = outcomeQueue.findIndex(c => c.priority);
        let outcome = priorityIdx >= 0 ? outcomeQueue.splice(priorityIdx, 1)[0] : outcomeQueue.shift();

        // Cards priced off the company's current health (e.g. the acquisition
        // offer) get their price computed now, at display time, against live state.
        if (outcome.valuation) outcome = buildAcquisitionOffer(outcome);

        const typeConfig = {
            positive: { emoji: "✨", color: "positive" },
            challenge: { emoji: "⚠️", color: "challenge" },
            opportunity: { emoji: "🚀", color: "opportunity" }
        };
        
        const config = typeConfig[outcome.type] || { emoji: "❓", color: "default" };
        let actionsHTML = generateOutcomeActions(outcome);
        
        return `
            <div class="business-card ${config.color} outcome-card">
                <div class="card-header ${config.color}">
                    <div class="card-type-wrapper">
                        <div><p>Outcome</p></div>
                        <div class="card-type">${outcome.type.toUpperCase()} ${config.emoji}</div>
                    </div>
                    <h2>${outcome.title}</h2>
                </div>
                <div class="card-svg-section">
                    <div class="svg-container">
                        <img class="card-img" data-src="${outcome.svg}" alt=""/>
                    </div>
                </div>
                <div class="card-body">
                    <div class="card-content">
                        <div class="content-desc">${outcome.description}</div>
                    </div>
                    ${outcome.followUp ? `
                        <div class="follow-up-section">
                            <strong>Follow-up:</strong> ${outcome.followUp}
                        </div>
                    ` : ''}
                    ${actionsHTML}
                </div>
            </div>
        `;
    }

    function generateOutcomeActions(outcome) {
        if (outcome.type === 'opportunity' && outcome.choices) {
            return `
                <div class="action-buttons">
                    ${outcome.choices.map((choice, index) => `
                        <button class="btn ${index === 0 ? 'btn-select' : 'btn-skip'}" 
                                onclick="handleOpportunityChoice(${JSON.stringify(choice).replace(/"/g, '&quot;')}, this)">
                            ${choice.text}
                        </button>
                    `).join('')}
                </div>
            `;
        } else if (outcome.type === 'challenge' && outcome.solutions) {
            return `
                <div class="solutions-section">
                    <h4>💡 Potential Solutions:</h4>
                    <ul class="solutions-list">
                        ${outcome.solutions.map(solution => `<li>${solution}</li>`).join('')}
                    </ul>
                </div>
                <div class="action-buttons">
                    <button class="btn btn-select" onclick="acknowledgeOutcome(${JSON.stringify(outcome).replace(/"/g, '&quot;')}, this)">
                        Acknowledge
                    </button>
                </div>
            `;
        }
        
        return `
            <div class="action-buttons">
                <button class="btn btn-select" onclick="acknowledgeOutcome(${JSON.stringify(outcome).replace(/"/g, '&quot;')}, this)">
                    Acknowledge
                </button>
            </div>
        `;
    }

// Enhanced milestone checking
    function checkRevenueMilestones() {
        if (!gameState.milestonesHit) gameState.milestonesHit = {};
        
        if (gameState.monthlyRevenue >= 1000 && !gameState.milestonesHit.first1k) {
            queueOutcomeCard(outcomeCards.revenueMilestones[0]);
            gameState.milestonesHit.first1k = true;
        }
        
        const netBurn = gameState.monthlyBurn - gameState.monthlyRevenue;
        if (netBurn <= 0 && gameState.monthlyRevenue > 2000 && !gameState.milestonesHit.profitable) {
            queueOutcomeCard(outcomeCards.revenueMilestones[1]);
            gameState.milestonesHit.profitable = true;
        }
    }

// Capstone: validating the idea AND shipping a product feature together make an
// MVP. Fires once, queuing a celebratory launch card that names both milestone
// cards the player picked to get there.
    function checkMVPLaunch() {
        if (!gameState.milestonesHit) gameState.milestonesHit = {};
        if (gameState.milestonesHit.mvpLaunched) return;

        const validationCard = gameState.selectedCards.find(c => c.category === 'validation');
        const productCard = gameState.selectedCards.find(c => c.category === 'product');
        if (!validationCard || !productCard) return;

        // Clone the template so the dynamic, player-specific description doesn't
        // mutate the shared data object.
        const launch = Object.assign({}, outcomeCards.mvpLaunch);
        launch.description =
            `You've turned an idea into something real — your MVP is live! `
            + `Two milestones came together to get you here:`
            + `<ul class="mvp-milestones">`
            + `<li><span class="mvp-check">✓</span> <strong>Validated the idea</strong> &mdash; ${validationCard.title}</li>`
            + `<li><span class="mvp-check">✓</span> <strong>Built your first feature</strong> &mdash; ${productCard.title}</li>`
            + `</ul>`;

        // Record how long it took to reach the MVP — the month it launched. This is
        // the only place timeToMVP is set during normal play (the selections modal
        // reads it). Before launch it stays 0 and the modal shows a dash.
        gameState.timeToMVP = gameState.currentMonth;

        queueOutcomeCard(launch);
        gameState.milestonesHit.mvpLaunched = true;

        // Reflect the new value immediately if the selections modal is pinned open.
        if (typeof updateOpenModals === 'function') updateOpenModals();
    }

