// Card loading for stack
    function loadMoreCards(cardCount = CARD_RENDER_BATCH_SIZE) {
        if (isLoading) return;
        isLoading = true;

        const container = domCache.simulatorContainer || document.getElementById('simulatorContainer');

        checkForOutcomes();
        checkRevenueMilestones();
        checkMVPLaunch();

        // Add outcome card if queued. Normally a 25% chance per batch, but a
        // priority card (e.g. the MVP launch capstone) is shown right away.
        if (outcomeQueue.length > 0 && (outcomeQueue.some(c => c.priority) || Math.random() > 0.75)) {
            const outcomeHTML = generateOutcomeCard();
            if (outcomeHTML) {
                const cardElement = document.createElement('div');
                cardElement.innerHTML = outcomeHTML;
                container.appendChild(cardElement.firstElementChild);
                cardCount--;
            }
        }

        const fragment = document.createDocumentFragment();
        for (let i = 0; i < cardCount; i++) {
            const cardHTML = generateBusinessCard();
            const cardElement = document.createElement('div');
            cardElement.innerHTML = cardHTML;
            fragment.appendChild(cardElement.firstElementChild);
        }
        container.appendChild(fragment);

        isLoading = false;

        // Double rAF to ensure initial opacity:0 renders before transition
        requestAnimationFrame(() => {
            requestAnimationFrame(() => {
                updateStackClasses();
            });
        });
    }

