(function ($) {
    const SWIPE_THRESHOLD = 90;     // px to trigger on slow drags
    const VELOCITY_THRESHOLD = 0.4; // px/ms to trigger on fast flicks
    const ROTATION_FACTOR = 0.12;   // degrees per px of horizontal drag

    let dragging = false;
    let lockedAxis = null; // 'h' | 'v' | null
    let startX = 0, startY = 0;
    let currentCard = null;
    let recentPositions = []; // [{x, t}] for velocity calc
    let lastTouchTime = 0;    // timestamp of the last touch event — used to ignore
                              // the synthetic mouse events mobile browsers dispatch
                              // after a tap (which otherwise flip the card twice)

    function clientXY(e) {
        const src = e.touches ? e.touches[0] : e;
        return { x: src.clientX, y: src.clientY };
    }

    function endXY(e) {
        const src = e.changedTouches ? e.changedTouches[0] : e;
        return { x: src.clientX, y: src.clientY };
    }

    // ── drag start ────────────────────────────────────────────────────────────
    $(document).on('mousedown touchstart', '.business-card.stack-active', function (e) {
        // The document-level touchstart listener is passive in mobile Chrome, so the
        // preventDefault below can't stop the ghost mouse events that trail a tap.
        // Track touches instead and drop any mouse event that follows one closely —
        // otherwise the ghost mousedown/mouseup re-runs the tap and re-flips the card.
        if (e.type === 'touchstart') lastTouchTime = Date.now();
        else if (Date.now() - lastTouchTime < 700) return;

        if ($(e.target).closest('button, a, input, select, textarea').length) return;

        // Management cards (e.g. the saved-games picker) opt out of drag-to-dismiss
        // so a stray swipe can't fling them away mid-decision.
        if (this.classList.contains('no-swipe')) return;

        const pt = clientXY(e);
        dragging = true;
        lockedAxis = null;
        startX = pt.x;
        startY = pt.y;
        currentCard = this;
        recentPositions = [{ x: pt.x, t: Date.now() }];

        $(this).css('transition', 'none');
        e.preventDefault();
    });

    // ── drag move ─────────────────────────────────────────────────────────────
    $(document).on('mousemove touchmove', function (e) {
        if (!dragging || !currentCard) return;

        const pt = clientXY(e);
        const dx = pt.x - startX;
        const dy = pt.y - startY;

        // Lock axis after first 6px so vertical scrolls don't become swipes
        if (!lockedAxis && (Math.abs(dx) > 6 || Math.abs(dy) > 6)) {
            lockedAxis = Math.abs(dx) >= Math.abs(dy) ? 'h' : 'v';
        }

        if (lockedAxis === 'v') {
            resetCard(currentCard);
            dragging = false;
            currentCard = null;
            return;
        }

        e.preventDefault();

        // Track recent positions (keep last 5) for velocity calculation
        recentPositions.push({ x: pt.x, t: Date.now() });
        if (recentPositions.length > 5) recentPositions.shift();

        const rot = dx * ROTATION_FACTOR;
        const vertDrift = dy * 0.15;
        $(currentCard).css('transform', `translateX(${dx}px) translateY(${vertDrift}px) rotate(${rot}deg)`);

        const progress = Math.min(Math.abs(dx) / SWIPE_THRESHOLD, 1);
        setIndicator(currentCard, dx > 0 ? 'add' : 'skip', progress);
    });

    // ── drag end ──────────────────────────────────────────────────────────────
    $(document).on('mouseup touchend', function (e) {
        if (e.type === 'touchend') lastTouchTime = Date.now();
        else if (Date.now() - lastTouchTime < 700) return; // ghost mouseup after a tap

        if (!dragging || !currentCard) return;
        dragging = false;

        const pt = endXY(e);
        const dx = pt.x - startX;

        // Compute velocity from the last two tracked positions
        let velocity = 0;
        if (recentPositions.length >= 2) {
            const a = recentPositions[recentPositions.length - 2];
            const b = recentPositions[recentPositions.length - 1];
            const dt = b.t - a.t;
            if (dt > 0) velocity = (b.x - a.x) / dt; // px/ms, signed
        }

        clearIndicator(currentCard);

        const pastDistThreshold = lockedAxis === 'h' && Math.abs(dx) >= SWIPE_THRESHOLD;
        const pastVelThreshold  = Math.abs(velocity) >= VELOCITY_THRESHOLD;

        if (pastDistThreshold || pastVelThreshold) {
            // Direction: velocity wins on fast flicks, dx wins on slow drags
            const goRight = pastVelThreshold ? velocity > 0 : dx > 0;
            const card = currentCard;
            currentCard = null;
            fling(card, goRight ? 'select' : 'skip');
        } else {
            resetCard(currentCard);
            // A press that never locked to an axis and barely moved is a tap, not a
            // drag — flip the card to reveal its full metrics (back face).
            const dy = pt.y - startY;
            const isTap = lockedAxis === null && Math.abs(dx) < 10 && Math.abs(dy) < 10;
            if (isTap && currentCard.classList.contains('flippable')) {
                flipCard(currentCard);
            }
            currentCard = null;
        }

        lockedAxis = null;
        recentPositions = [];
    });

    // ── helpers ───────────────────────────────────────────────────────────────
    function resetCard(card) {
        $(card).css('transition', '').css('transform', '');
    }

    // Toggle the card's face and play the lift-and-flip keyframes. The animation
    // is restarted explicitly (clear + reflow) so repeated taps always replay it,
    // and the direction is chosen so the card flips back the way it came.
    function flipCard(card) {
        const inner = card.querySelector('.card-inner');
        const toBack = !card.classList.contains('flipped');
        card.classList.toggle('flipped');
        if (!inner) return;

        inner.style.animation = 'none';
        void inner.offsetWidth; // force reflow so the animation can restart
        inner.style.animation = (toBack ? 'cardFlipToBack' : 'cardFlipToFront') +
            ' 0.6s cubic-bezier(0.4, 0, 0.2, 1) forwards';

        // Sweep a diagonal sheen across the ARRIVING face in time with the flip.
        // The direction class selects which face's sheen runs, so the two faces'
        // sheens never overlap into an "X". Restart it (clear + reflow) so it
        // replays on every tap, and drop the classes when done.
        card.classList.remove('flipping', 'flip-to-back', 'flip-to-front');
        void card.offsetWidth;
        card.classList.add('flipping', toBack ? 'flip-to-back' : 'flip-to-front');
        clearTimeout(card._sheenTimer);
        card._sheenTimer = setTimeout(function () {
            card.classList.remove('flipping', 'flip-to-back', 'flip-to-front');
        }, 600);
    }

    function fling(card, action) {
        // Mark the card so selectCard/skipCard know not to re-animate it
        card.dataset.swiping = 'true';

        const targetX = action === 'select' ? '140%' : '-140%';
        const rot     = action === 'select' ? '20deg'  : '-20deg';

        $(card).css({
            transition: 'transform 0.28s ease-in, opacity 0.2s ease-in',
            transform: `translateX(${targetX}) rotate(${rot})`,
            opacity: 0
        });

        // Fire the button immediately — selectCard/skipCard will see dataset.swiping
        // and skip their own dismiss animation, just handling game state + DOM cleanup
        const btn = card.querySelector(action === 'select' ? '.btn-select' : '.btn-skip');
        if (btn) btn.click();
    }

    // Stamp overlay (ADD / SKIP) shown while dragging
    function setIndicator(card, direction, progress) {
        let el = card.querySelector('.swipe-stamp');
        if (!el) {
            el = document.createElement('div');
            el.className = 'swipe-stamp';
            el.setAttribute('aria-hidden', 'true');
            card.appendChild(el);
        }
        el.classList.toggle('stamp-add',  direction === 'add');
        el.classList.toggle('stamp-skip', direction === 'skip');
        el.textContent = direction === 'add' ? 'ADD' : 'SKIP';
        el.style.opacity = progress;
    }

    function clearIndicator(card) {
        const el = card && card.querySelector('.swipe-stamp');
        if (el) el.style.opacity = 0;
    }

    // ── keyboard controls ───────────────────────────────────────────────────────
    // Mirror the swipe gestures for keyboard users: ← skips, → adds, and Enter / F
    // flips the focused card. Skip/Add fall back to whichever action button the
    // card actually has, so outcome cards (no Skip) just ignore the missing one.
    function triggerAction(card, action) {
        if (card.dataset.swiping) return; // already animating out
        const selector = action === 'select' ? '.btn-select' : '.btn-skip';
        if (!card.querySelector(selector)) return; // this card has no such action
        fling(card, action);
    }

    // Track input modality so the next-card focus ring only shows for keyboard use.
    $(document).on('pointerdown', function () {
        if (window.gameState) gameState.lastActionViaKeyboard = false;
    });

    $(document).on('keydown', function (e) {
        // Bail only when keyboard focus is actually inside an open dialog — there the
        // keys belong to the dialog. On desktop the metrics/selections panels are
        // pinned open beside the cards (see the min-width:1330px layout), so a merely
        // visible panel must not disable card shortcuts; defer only while the user is
        // focused within one.
        if ($(e.target).closest('.selections-modal, .company-metrics-modal, .help-modal').length) return;

        const card = document.querySelector('.business-card.stack-active');
        if (!card) return;

        // Whether focus is on something that handles its own keys (a button, link,
        // or form field) — Enter there should activate it, not flip the card.
        const onInteractive = $(e.target).closest('button, a, input, select, textarea').length > 0;
        // 'f' types into fields but does nothing on a button/link, so it can flip
        // even when focus rests on a control (e.g. the trigger button after opening
        // a pinned panel) — only a text field should swallow it.
        const inTextField = $(e.target).closest('input, textarea, select').length > 0;

        switch (e.key) {
            case 'ArrowRight':
                e.preventDefault();
                if (window.gameState) gameState.lastActionViaKeyboard = true;
                triggerAction(card, 'select');
                break;
            case 'ArrowLeft':
                e.preventDefault();
                if (window.gameState) gameState.lastActionViaKeyboard = true;
                triggerAction(card, 'skip');
                break;
            case 'Enter':
                if (!onInteractive && card.classList.contains('flippable')) {
                    e.preventDefault();
                    flipCard(card);
                }
                break;
            case 'f':
            case 'F':
                if (!inTextField && card.classList.contains('flippable')) {
                    e.preventDefault();
                    flipCard(card);
                }
                break;
            case 'Escape':
                // No modal is open here (guarded above), so Esc just flips a
                // flipped card back to its front face.
                if (card.classList.contains('flipped')) {
                    e.preventDefault();
                    flipCard(card);
                }
                break;
        }
    });

})(jQuery);

